function Toast({ message, type, onClose }) {
  useEffect(() => {
    const timer = setTimeout(onClose, 4000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const colors = {
    success: { bg: "#2b7574", icon: "OK" },
    error:   { bg: "linear-gradient(135deg, #ef4444, #dc2626)", icon: "!" },
    info:    { bg: "linear-gradient(135deg, #2b7574, #e2e2e0)", icon: "i" },
  };
  const c = colors[type] || colors.info;
     
  return (
    <div style={{
      position: "fixed", top: 24, right: 24, zIndex: 9999,
      background: c.bg, color: "#fff", padding: "14px 24px",
      borderRadius: 12, boxShadow: "0 8px 32px rgba(32,38,38,0.14)",
      display: "flex", alignItems: "center", gap: 12,
      animation: "slideIn 0.4s ease", minWidth: 280, maxWidth: 420,
      fontFamily: "'Inter', 'Segoe UI', sans-serif",
    }}>
      <span style={{ fontSize: 18, fontWeight: 500, width: 28, height: 28,
        borderRadius: "50%", background: "rgba(255,255,255,0.25)",
        display: "flex", alignItems: "center", justifyContent: "center"
      }}>{c.icon}</span>
      <span style={{ flex: 1, fontSize: 14, fontWeight: 500 }}>{message}</span>
      <button onClick={onClose} style={{
        background: "none", border: "none", color: "#fff",
        cursor: "pointer", fontSize: 18, opacity: 0.7, padding: 0,
      }}>x</button>
    </div>
  );
}

function CheckIcon({ size = 14 }) {
  return (
    <svg width={size} height={size} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
    </svg>
  );
}

