        {activeTab === 'Welcome' && (
          <div style={{ animation: "fadeUp 0.5s ease" }}>
            <div className="card-hover" style={{
              display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
              minHeight: 300, background: "linear-gradient(135deg, #ffffff 0%, #ffffff 100%)",
              borderRadius: 20, boxShadow: "0 4px 24px rgba(0,0,0,0.06)", padding: 48,
              textAlign: "center", border: "1px solid rgba(0,0,0,0.06)",
            }}>
              <h2 style={{ fontSize: 32, fontWeight: 500, color: "#000000", marginBottom: 8 }}>{getGreeting()}, Admin!</h2>
              <p style={{ fontSize: 16, color: "rgba(0,0,0,0.58)", maxWidth: 400 }}>Select an option from the navigation menu to get started.</p>

              <div style={{ display: "flex", gap: 16, marginTop: 32, flexWrap: "wrap", justifyContent: "center" }}>
                {[
                  { label: "Users", count: users.length, color: "#000000" },
                  { label: "Departments", count: departments.length, color: "#000000" },
                  { label: "Assignments", count: assignments.length, color: "#000000" },
                ].map(s => (
                  <div key={s.label} style={{
                    background: "#fff", borderRadius: 12, padding: "16px 24px",
                    boxShadow: "0 2px 12px rgba(0,0,0,0.06)", minWidth: 110,
                    border: "1px solid rgba(0,0,0,0.10)",
                  }}>
                    <p style={{ fontSize: 28, fontWeight: 500, color: s.color, margin: 0 }}>{s.count}</p>
                    <p style={{ fontSize: 12, fontWeight: 500, color: "rgba(0,0,0,0.42)", margin: 0, textTransform: "uppercase", letterSpacing: 0.5 }}>{s.label}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

