            {manualStep === 1 && (
              <div className="card-hover" style={{ background: "#fff", borderRadius: 16, boxShadow: "0 2px 12px rgba(0,0,0,0.06)", border: "1px solid rgba(0,0,0,0.10)", overflow: "hidden" }}>
                <div style={{ padding: "20px 24px", borderBottom: "2px solid #e2e2e0", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div>
                    <h2 style={{ color: "#000000", fontSize: 17, fontWeight: 500, margin: 0 }}>Step 1: Select Reviewer</h2>
                    <p style={{ color: "rgba(0,0,0,0.58)", fontSize: 13, margin: "4px 0 0" }}>Choose who will receive the assignment email</p>
                  </div>
                  <span style={{ background: "linear-gradient(135deg, #e2e2e0, #ffffff)", color: "#000000", fontSize: 12, padding: "6px 14px", borderRadius: 20, fontWeight: 500 }}>
                    {manualReviewer.length} selected
                  </span>
                </div>

                <div style={{ padding: "16px 24px", borderBottom: "1px solid #e2e2e0", display: "flex", gap: 12, alignItems: "center" }}>
                  <div style={{ position: "relative", flex: 1 }}>
                    <svg style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "rgba(0,0,0,0.42)" }} width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                    </svg>
                    <input
                      placeholder="Search users..."
                      value={Reviewerearch}
                      onChange={e => setReviewerearch(e.target.value)}
                      style={{ width: "100%", padding: "10px 12px 10px 40px", border: "1px solid #e2e8f0", borderRadius: 10, outline: "none", fontSize: 13, transition: "all 0.2s", boxSizing: "border-box" }}
                    />
                  </div>
                  <button onClick={selectAllReviewer} style={{
                    background: "#e2e2e0", border: "1px solid #e2e8f0", padding: "10px 16px", borderRadius: 10,
                    cursor: "pointer", fontWeight: 500, fontSize: 12, color: "#000000", whiteSpace: "nowrap", transition: "all 0.2s",
                  }}>
                    {users.filter(u => u.name.toLowerCase().includes(Reviewerearch.toLowerCase())).every(u => manualReviewer.includes(u.user_id)) ? "Deselect All" : "Select All"}
                  </button>
                </div>

                <div style={{ maxHeight: 400, overflowY: "auto", padding: "8px 12px" }}>
                  {users.filter(u => u.name.toLowerCase().includes(Reviewerearch.toLowerCase())).map(u => {
                    const isSelected = manualReviewer.includes(u.user_id);
                    return (
                      <div
                        key={u.user_id}
                        className="check-item"
                        onClick={() => toggleRecipient(u.user_id)}
                        style={{
                          display: "flex", alignItems: "center", gap: 12,
                          padding: "10px 14px", borderRadius: 10, marginBottom: 2,
                          background: isSelected ? "#e2e2e0" : "transparent",
                          border: isSelected ? "1px solid #2b7574" : "1px solid transparent",
                        }}
                      >
                        <div style={{
                          width: 20, height: 20, borderRadius: 6,
                          border: isSelected ? "none" : "2px solid #cbd5e0",
                          background: isSelected ? "#2b7574" : "#fff",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          transition: "all 0.2s", flexShrink: 0,
                        }}>
                          {isSelected && <CheckIcon size={13} />}
                        </div>
                        <div style={{
                          width: 36, height: 36, borderRadius: "50%",
                          background: isSelected ? "#2b7574" : "linear-gradient(135deg, #e2e8f0, #cbd5e0)",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          color: isSelected ? "#fff" : "rgba(0,0,0,0.58)", fontWeight: 500, fontSize: 14, flexShrink: 0,
                        }}>
                          {u.name.charAt(0)}
                        </div>
                        <div style={{ flex: 1 }}>
                          <p style={{ fontWeight: 500, color: "#000000", margin: 0, fontSize: 13 }}>{u.name}</p>
                          <p style={{ fontSize: 11, color: "rgba(0,0,0,0.42)", margin: 0 }}>{u.email}</p>
                        </div>
                        <span style={{ background: "rgba(0,0,0,0.06)", color: "#2b7574", padding: "3px 10px", borderRadius: 6, fontWeight: 500, fontSize: 11 }}>{getUserDepartmentName(u.user_id)}</span>
                      </div>
                    );
                  })}
                </div>

                <div style={{ padding: "16px 24px", borderTop: "1px solid #e2e2e0", display: "flex", justifyContent: "flex-end" }}>
                  <button
                    onClick={() => { if (manualReviewer.length > 0) setManualStep(2); else showToast("Select at least one recipient", "error"); }}
                    className="btn-primary"
                    style={{
                      background: manualReviewer.length > 0 ? "#2b7574" : "#e2e8f0",
                      color: manualReviewer.length > 0 ? "#fff" : "rgba(0,0,0,0.42)",
                      padding: "10px 28px", borderRadius: 10, border: "none", cursor: "pointer",
                      fontWeight: 500, fontSize: 14, display: "flex", alignItems: "center", gap: 8,
                    }}
                  >
                    Next Step
                    <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                  </button>
                </div>
              </div>
            )}

